  ('bookkeeper-moex-01398', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列何項農作物之銷售為我國「加值型及非加值型營業稅法」第8條所列之免徵範圍？', '["麵粉", "黃豆", "大豆", "小米"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
